// src/App.js
import React from 'react'; // Importando a biblioteca React para construir a interface do usuário
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom'; // Importando o BrowserRouter, Routes e Route para gerenciar a navegação
import Navbar from './components/Navbar'; // Importando o componente Navbar que contém a barra de navegação
import Header from './components/Header'; // Importando o componente Header que exibe o cabeçalho
import Dashboard from './components/Dashboard'; // Importando o componente Dashboard
import Calendar from './components/Calendar'; // Importando o componente Calendar que apresenta um calendário
import Atendimento from './components/gestao/atendimento'; // Importando o componente Atendimento da seção de gestão
import Pessoa from './components/gestao/pessoa'; // Importando o componente Pessoa da seção de gestão
import Workflow from './components/gestao/workflow'; // Importando o componente Workflow da seção de gestão
import Timesheet from './components/gestao/timesheet'; // Importando o componente Timesheet da seção de gestão
import RelatoriosGestao from './components/gestao/relatorios'; // Importando o componente de relatórios de gestão
import ListaAtividades from './components/atividades/lista_atividades'; // Importando o componente que lista as atividades
import PainelTarefas from './components/atividades/painel_tarefas'; // Importando o componente Painel de Tarefas
import KanbanTarefas from './components/atividades/kanban_tarefas'; // Importando o componente Kanban de Tarefas
import RelatoriosAtividades from './components/atividades/relatorios'; // Importando o componente de relatórios de atividades
import Processos from './components/processos/processos'; // Importando o componente Processos
import Intimacoes from './components/processos/intimacoes'; // Importando o componente Intimações
import CentralCaptura from './components/processos/central_captura_processos'; // Importando o componente Central de Captura de Processos
import AndamentosProcessuais from './components/processos/andamentos_processuais'; // Importando o componente de Andamentos Processuais
import RelatoriosProcessos from './components/processos/relatorios'; // Importando o componente de relatórios de processos
import ReceitasDespesas from './components/financeiro/receitas_despesas'; // Importando o componente Receitas e Despesas
import ExtratoConta from './components/financeiro/extrato_conta'; // Importando o componente Extrato de Conta
import Solicitacoes from './components/financeiro/solicitacoes'; // Importando o componente de Solicitações
import IntegracaoReceitas from './components/financeiro/integracao_receitas'; // Importando o componente de Integração de Receitas
import IntegracaoDespesas from './components/financeiro/integracao_despesas'; // Importando o componente de Integração de Despesas
import RelatoriosFinanceiro from './components/financeiro/relatorios'; // Importando o componente de relatórios financeiros
import Documentos from './components/documentos/documentos'; // Importando o componente Documentos
import ModelosDocumentos from './components/documentos/modelos_documentos'; // Importando o componente Modelos de Documentos
import Conexoes from './components/extensoes/conexoes'; // Importando o componente Conexões
import RelatoriosExtensoes from './components/extensoes/relatorios'; // Importando o componente de relatórios de extensões
import './App.css'; // Importando o arquivo CSS para estilos da aplicação

const App = () => {
  return (
    <Router>
      <div className="app-container"> {/* Contêiner principal da aplicação */}
        <Navbar /> {/* Componente da barra de navegação */}
        <Header /> {/* Componente do cabeçalho */}
        <Routes> {/* Gerenciando as diferentes rotas da aplicação */}
          <Route path="/" element={<Dashboard />} /> {/* Rota para o Dashboard */}
          <Route path="/gestao/atendimento" element={<Atendimento />} /> {/* Rota para o componente Atendimento */}
          <Route path="/gestao/pessoa" element={<Pessoa />} /> {/* Rota para o componente Pessoa */}
          <Route path="/gestao/workflow" element={<Workflow />} /> {/* Rota para o componente Workflow */}
          <Route path="/gestao/timesheet" element={<Timesheet />} /> {/* Rota para o componente Timesheet */}
          <Route path="/gestao/relatorios" element={<RelatoriosGestao />} /> {/* Rota para os relatórios de gestão */}
          <Route path="/atividades" element={<ListaAtividades />} /> {/* Rota para listar atividades */}
          <Route path="/atividades/painel" element={<PainelTarefas />} /> {/* Rota para o painel de tarefas */}
          <Route path="/atividades/kanban" element={<KanbanTarefas />} /> {/* Rota para o kanban de tarefas */}
          <Route path="/atividades/relatorios" element={<RelatoriosAtividades />} /> {/* Rota para os relatórios de atividades */}
          <Route path="/processos" element={<Processos />} /> {/* Rota para o componente Processos */}
          <Route path="/processos/intimacoes" element={<Intimacoes />} /> {/* Rota para o componente Intimações */}
          <Route path="/processos/central-captura" element={<CentralCaptura />} /> {/* Rota para o componente Central de Captura */}
          <Route path="/processos/andamentos" element={<AndamentosProcessuais />} /> {/* Rota para os andamentos processuais */}
          <Route path="/processos/relatorios" element={<RelatoriosProcessos />} /> {/* Rota para os relatórios de processos */}
          <Route path="/financeiro" element={<ReceitasDespesas />} /> {/* Rota para o componente Receitas e Despesas */}
          <Route path="/financeiro/extrato" element={<ExtratoConta />} /> {/* Rota para o extrato de conta */}
          <Route path="/financeiro/solicitacoes" element={<Solicitacoes />} /> {/* Rota para as solicitações financeiras */}
          <Route path="/financeiro/integracao-receitas" element={<IntegracaoReceitas />} /> {/* Rota para integração de receitas */}
          <Route path="/financeiro/integracao-despesas" element={<IntegracaoDespesas />} /> {/* Rota para integração de despesas */}
          <Route path="/financeiro/relatorios" element={<RelatoriosFinanceiro />} /> {/* Rota para os relatórios financeiros */}
          <Route path="/documentos" element={<Documentos />} /> {/* Rota para o componente Documentos */}
          <Route path="/documentos/modelos" element={<ModelosDocumentos />} /> {/* Rota para os modelos de documentos */}
          <Route path="/extensoes" element={<Conexoes />} /> {/* Rota para o componente Conexões */}
          <Route path="/extensoes/relatorios" element={<RelatoriosExtensoes />} /> {/* Rota para os relatórios de extensões */}
        </Routes>
        <div className="calendar-container"> {/* Contêiner para o calendário */}
          <Calendar /> {/* Componente do calendário */}
        </div>
      </div>
    </Router>
  );
};

export default App; // Exportando o componente App
